var rows = msg.payload;
if (!rows || rows.length === 0) return null;
var latest = rows[0];
var sorted = rows.slice().reverse();

// Chart helper
function makeChart(field, label) {
  var pts = sorted.map(function(r) {
    return { x: new Date(r.timestamp).getTime(), y: r[field] };
  });
  return { payload: [{ series:[label], data:[pts], labels:[label] }] };
}

// Card HTML
var cardHtml = '<div style="display:flex;gap:12px;flex-wrap:wrap;padding:8px;">'
  + '<div style="flex:1;min-width:110px;background:linear-gradient(135deg,#f94144,#f3722c);border-radius:12px;padding:14px;text-align:center;color:#fff;">'
  + '<div style="font-size:24px;">🌡️</div><div style="font-size:26px;font-weight:bold;">' + latest.temperature.toFixed(1) + '°C</div>'
  + '<div style="font-size:11px;opacity:0.85;">Temperature</div></div>'
  + '<div style="flex:1;min-width:110px;background:linear-gradient(135deg,#0077b6,#00b4d8);border-radius:12px;padding:14px;text-align:center;color:#fff;">'
  + '<div style="font-size:24px;">💧</div><div style="font-size:26px;font-weight:bold;">' + latest.humidity.toFixed(1) + '%</div>'
  + '<div style="font-size:11px;opacity:0.85;">Humidity</div></div>'
  + '<div style="flex:1;min-width:110px;background:linear-gradient(135deg,#1b4332,#52b788);border-radius:12px;padding:14px;text-align:center;color:#fff;">'
  + '<div style="font-size:24px;">🌬️</div><div style="font-size:26px;font-weight:bold;">' + latest.pressure.toFixed(1) + '</div>'
  + '<div style="font-size:11px;opacity:0.85;">Pressure hPa</div></div>'
  + '<div style="flex:1;min-width:110px;background:linear-gradient(135deg,#f8961e,#ffd60a);border-radius:12px;padding:14px;text-align:center;color:#fff;">'
  + '<div style="font-size:24px;">☀️</div><div style="font-size:26px;font-weight:bold;">' + Math.round(latest.light_level) + '</div>'
  + '<div style="font-size:11px;opacity:0.85;">Light lux</div></div></div>';

// Table HTML
var tableHtml = '<div style="padding:4px;overflow-x:auto;">'
  + '<table style="width:100%;border-collapse:collapse;font-size:13px;">'
  + '<thead><tr style="background:#1f2937;color:#e5e7eb;">'
  + '<th style="padding:8px 10px;text-align:left;">🕐 Timestamp</th>'
  + '<th style="padding:8px 10px;text-align:center;">🌡️ Temp °C</th>'
  + '<th style="padding:8px 10px;text-align:center;">💧 Humid %</th>'
  + '<th style="padding:8px 10px;text-align:center;">🌬️ Press hPa</th>'
  + '<th style="padding:8px 10px;text-align:center;">☀️ Light lux</th>'
  + '</tr></thead><tbody>';

rows.forEach(function(row, i) {
  var bg = i % 2 === 0 ? '#111827' : '#1a2535';
  var tColor = row.temperature > 35 ? '#f94144' : row.temperature > 28 ? '#f8961e' : '#43aa8b';
  var hColor = row.humidity > 80 ? '#48cae4' : row.humidity > 60 ? '#00b4d8' : '#90e0ef';
  var lColor = row.light_level > 700 ? '#f8961e' : row.light_level > 300 ? '#ffd60a' : '#adb5bd';
  tableHtml += '<tr style="background:' + bg + ';">'
    + '<td style="padding:6px 10px;color:#9ca3af;">' + row.timestamp + '</td>'
    + '<td style="padding:6px 10px;text-align:center;font-weight:bold;color:' + tColor + ';">' + row.temperature.toFixed(1) + '</td>'
    + '<td style="padding:6px 10px;text-align:center;font-weight:bold;color:' + hColor + ';">' + row.humidity.toFixed(1) + '</td>'
    + '<td style="padding:6px 10px;text-align:center;color:#52b788;">' + row.pressure.toFixed(1) + '</td>'
    + '<td style="padding:6px 10px;text-align:center;color:' + lColor + ';">' + Math.round(row.light_level) + '</td>'
    + '</tr>';
});
tableHtml += '</tbody></table></div>';

return [
  [{payload: latest.temperature}],
  [{payload: latest.humidity}],
  [{payload: latest.pressure}],
  [{payload: latest.light_level}],
  [makeChart('temperature','Temp °C')],
  [makeChart('pressure','Pressure hPa')],
  [{payload: cardHtml}],
  [{payload: tableHtml}]
];
